solution_code:
#include <stdio.h>
#include <stdlib.h>
typedef struct { float width; float height; } Rectangle;
int main(void) {
    Rectangle *r = malloc(sizeof(Rectangle));
    if (!r) return 1;
    r->width  = 5.0f;
    r->height = 3.0f;
    printf("Largeur : %.1f\n", r->width);
    printf("Hauteur : %.1f\n", r->height);
    printf("Aire : %.1f\n", r->width * r->height);
    printf("Perimetre : %.1f\n", 2.0f * (r->width + r->height));
    free(r);
    return 0;
}

