 * Struct Circle sur le tas avec -> pour aire et perimetre
 * malloc(sizeof(T)) alloue sur le tas, -> accede aux champs.
 * =========================================================== */
typedef struct { float radius; } Circle;

void example_circle(void) {
    Circle *c = malloc(sizeof(Circle));
    if (!c) return;
    c->radius = 4.0f;
    float pi = 3.14159f;
    printf("Rayon : %.1f\n", c->radius);
    printf("Aire : %.2f\n", pi * c->radius * c->radius);
    printf("Circonference : %.2f\n", 2.0f * pi * c->radius);
    free(c);
}
/* Resultat: Rayon : 4.0 / Aire : 50.27 / Circonference : 25.13 */

